var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_SHADE","text":{"KOREA":"어째서야......? 왜, 나한테......!","JPN":"どうしてなの……？　なんで、私に……！","ENG":"Why? Why would you...","TWN":"為什麼……？為什麼這麼對我……！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_SHADE","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_METAMOR_01"},{"id":"L5_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"다시 일어났어요. 저렇게 만신창이가 됐는데......","JPN":"また起き上がりました。もうあんなにボロボロなのに……","ENG":"She got up again. Even after that brutal beating...","TWN":"又站起來了。都遍體鱗傷了還……"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"몇 번을 해치워도 말이지. 눈치없는 점은 누구랑 똑같군.","JPN":"何度倒してもダメか。空気が読めないところは誰かさんソックリだな。","ENG":"She never gives up, does she. She's as clueless as someone I know.","TWN":"已經打倒多次了，觀察力很遲鈍這一點還真像某人。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니한테 눈치없이 구는 간 큰 사람이 다 있어요?! 충격!","JPN":"リタお姉ちゃんにそんな気兼ねなくふるまう大胆な人がいるんですか？　ショック！","ENG":"Who else is bold enough to be that clueless around you? That's so shocking!","TWN":"誰那麼大膽，對姐姐這麼沒觀察力？！太厲害了！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......됐어. 말을 말자.","JPN":"……まあいい。","ENG":"Forget it. What did I expect.","TWN":"……算了，對牛彈琴。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그런데 이제 어쩌죠? 저희가 못 막으면 다른 사람들은 죽을지도 몰라요.","JPN":"でもどうしましょう？　私たちで止められなかったら誰か怪我するかもしれません。","ENG":"What should we do now? If we don't stop her, she'll end up killing everyone else.","TWN":"但是現在怎麼辦？如果我們攔不住她，其他人可能會死的。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"호라이즌, 네 눈을 잠시 빌려야겠어.","JPN":"ホライズン、ちょっと目を貸せ。","ENG":"Horizon, I'm going to need your eyes for a sec.","TWN":"地平線，看來我要借一下你的眼睛了。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"침식파를 분석한 결과, 특별한 성질을 발견했습니다. 무슨 뜻이냐면......","JPN":"侵食波を分析した結果、変わった性質を発見しました。つまり……","ENG":"Corruption Ray analysis has identified a unique trait. What this means is...","TWN":"侵蝕波分析結果，發現特殊性質。意思就是……"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"알아듣기 쉽게 요점만 말해.","JPN":"わかりやすく要点だけ言え。","ENG":"Keep it short and sweet.","TWN":"說重點。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"적은 특정한 매개체를 통해 이 공간에 투영된 허상입니다.","JPN":"敵は特定の媒体を通じてこの空間に投影された虚像です。","ENG":"The enemy is an illusion projected into this space via a specific medium.","TWN":"這是敵人通過特定媒介投影到這個空間的幻象。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"사진 속에서 나왔다는 대시의 증언을 감안하면, 그 사진이 매개체로 추정되는군요.","JPN":"写真の中から出てきたというダッシュの証言からして、その写真が媒体と推定されます。","ENG":"Dash said that she came out of a photo, so that photograph must be the medium.","TWN":"黛西說她是從照片裡出來的，我推測這張照片就是媒介。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그 사진만 찾아서 없애면 해결될 거란 뜻이군.","JPN":"その写真を見つけて抹消すれば解決するってことか。","ENG":"So we just need to get rid of that photo.","TWN":"也就是說只要找到那張照片並且毀掉就可以了吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"꼬맹이. 내가 저 그림자를 붙잡아 두는 동안 사진을 찾아 찢어 버려.","JPN":"よし、ガキ。私が時間稼ぎをするから写真を見つけて破ってしまえ。","ENG":"Kid. Find that photo and destroy it while I keep the Shadow pinned down.","TWN":"小鬼，在我抓那個暗影的時候，你要找到照片並撕毀。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"네넹! 맡겨 주세요!","JPN":"はいっ！　任せてください！","ENG":"Oki! You can count on me!","TWN":"好！包在我身上！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_SHADE","text":{"KOREA":"아아아아아아!!","JPN":"アアアァァァァ！！","ENG":"Aaaaaah!","TWN":"啊啊啊啊啊！！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_SHADE","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"네 상대는 꼬맹이가 아니라 나야.","JPN":"お前の相手はこの私だ。","ENG":"Hey, pick on someone... not your own size!","TWN":"你的對手不是她，是我。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L26_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_SHADE","text":{"KOREA":"아, 아아......","JPN":"あ、ああ……","ENG":"Ah, aah...","TWN":"啊，啊啊……"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_SHADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_SHADE","text":{"KOREA":"언...... 니......? 나, 너무 아파......! 이제, 싫어......!","JPN":"お姉……ちゃん……？　私、痛いよ……！　もう、やだよ……！","ENG":"Sis? I'm... in so much pain... I don't... want to do this... anymore!","TWN":"姐……姐姐……？我、我好痛……！不、不要……！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_SHADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"미안하군. 동생 한 명 더 받아 주기엔 지금 있는 꼬맹이도 벅차.","JPN":"悪いな。家族は今いるガキ一人だけでも精一杯でな。","ENG":"Sorry. I'm busy enough babysitting one lousy kid already.","TWN":"對不起了。一個小鬼足夠我頭疼了，不需要再多一個。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RITA_HORIZON_NULL_ON","text":{"KOREA":"그러니 넌 여기서 얌전히 사라져 줘야겠어. 그림자.","JPN":"だからお前にはここで消えてもらう、シャドウ。","ENG":"So you'd better just shut up and disappear now. Shadow.","TWN":"所以你就在這裡乖乖消失吧，暗影。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};